class Solution:
    def rob(self, nums: list[int]) -> int:
        a = b = 0                    # a:到上上家的最大;b:到上一家的最大
        for x in nums:
            a, b = b, max(b, a + x)  # 当前家:不偷(b) 或 偷(a + x)
        return b
